(()=>{var r=document.querySelectorAll(".prose h2, .prose h3, .prose h4"),s=document.querySelectorAll("#TableOfContents a");if(r.length&&s.length){let n=new IntersectionObserver(e=>{for(let t of e)if(t.isIntersecting){let c=t.target.id;s.forEach(o=>{o.classList.toggle("toc-active",o.getAttribute("href")===`#${c}`)});break}},{rootMargin:"-20px 0px -70% 0px",threshold:0});r.forEach(e=>n.observe(e))}})();
